package scr.state.org.apache.karaf.scr.state;

public class ScrBundleStateService implements BundleStateService { ServiceComponentRuntime scr ; public ScrBundleStateService ( ServiceComponentRuntime scr ) { this . scr = scr ; } @ Override public String getName ( ) { return BundleStateService . NAME_DS ; } @ Override public String getDiag ( Bundle bundle ) { StringBuilder sb = new StringBuilder ( ) ; for ( ComponentDescriptionDTO desc : scr . getComponentDescriptionDTOs ( bundle ) ) { for ( ComponentConfigurationDTO cfg : scr . getComponentConfigurationDTOs ( desc ) ) { if ( cfg . state != ComponentConfigurationDTO . ACTIVE && cfg . state != ComponentConfigurationDTO . SATISFIED ) { sb . append ( cfg . description . name ) . append ( " (" ) . append ( cfg . id ) . append ( ")\n" ) ; if ( ( cfg . state & ComponentConfigurationDTO . UNSATISFIED_CONFIGURATION ) != 0 ) { sb . append ( "  missing configurations: " ) ; boolean first = true ; for ( String s : cfg . description . configurationPid ) { if ( ! first ) { sb . append ( ", " ) ; } sb . append ( s ) ; first = false ; } sb . append ( "\n" ) ; } if ( ( cfg . state & ComponentConfigurationDTO . UNSATISFIED_REFERENCE ) != 0 ) { sb . append ( "  missing references: " ) ; boolean first = true ; for ( UnsatisfiedReferenceDTO ur : cfg . unsatisfiedReferences ) { if ( ! first ) { sb . append ( ", " ) ; } sb . append ( ur . name ) ; first = false ; } sb . append ( "\n" ) ; } } } } return sb . toString ( ) ; } @ Override public BundleState getState ( Bundle bundle ) { if ( bundle . getState ( ) == Bundle . ACTIVE ) { for ( ComponentDescriptionDTO desc : scr . getComponentDescriptionDTOs ( bundle ) ) { for ( ComponentConfigurationDTO cfg : scr . getComponentConfigurationDTOs ( desc ) ) { if ( cfg . state != ComponentConfigurationDTO . ACTIVE && cfg . state != ComponentConfigurationDTO . SATISFIED ) { return BundleState . Waiting ; } } } } return BundleState . Unknown ; } }